//

void I_Quit (void)
{
    atexit_listentry_t *entry;

    // Run through all exit functions

    entry = exit_funcs;

    while (entry != NULL)
    {
        entry->func();
        entry = entry->next;
    }

#if ORIGCODE
    SDL_Quit();

    exit(0);
#endif
}

